Code.Terraform:
```hcl
# Terraform：确保 Lightsail 实例上没有开放的公共端口
resource "aws_lightsail_instance_public_ports" "<example_resource_name>" {
  instance_name = "<example_resource_name>"

  # 关键：没有 port_info 块 -> 没有配置公共端口（全部关闭）
  dynamic "port_info" {
    for_each = []
    content {
      from_port = 0
      to_port   = 0
      protocol  = "tcp"
    }
  }
}
```
